 26	import { isEmpty } from "lodash-es";
 27	import { nodeHealthCheckKind } from "../../data/model";
 28	
 29	export type BreadCrumbsProps = {
 30	  breadcrumbs: { name: string; path: string }[];
 31	};
 32	
 33	export type PageHeadingProps = {
 34	  breadcrumbs?: { name: string; path: string }[];
 35	  children?: React.ReactChildren;
 36	  menuActions?: Action[];
 37	  resourceKeys?: string[];
 38	  title?: string | JSX.Element;
 39	  icon?: React.ComponentType<{ obj?: K8sResourceKind }>;
 40	  helpText?: React.ReactNode;
 41	  obj?: K8sResourceKind;
 42	  statusIcon?: React.ReactElement;
 43	  statusText?: string;
 44	  kind?: string;
 45	  detail?: boolean;
 46	};
 47	
 48	export const BreadCrumbs: React.SFC<BreadCrumbsProps> = ({ breadcrumbs }) => (
 49	  <Breadcrumb>
 50	    {breadcrumbs.map((crumb, i, { length }) => {
 51	      const isLast = i === length - 1;
 52	
 53	      return (
 54	        <BreadcrumbItem key={i} isActive={isLast}>
 55	          {isLast ? (
 56	            crumb.name
 57	          ) : (
 58	            <Link
 59	              className="pf-c-breadcrumb__link"
 60	              to={crumb.path}
 61	              data-test-id={`breadcrumb-link-${i}`}
 62	            >
 63	              {crumb.name}
 64	            </Link>
 65	          )}
 66	        </BreadcrumbItem>
 67	      );
 68	    })}
 69	  </Breadcrumb>
 70	);
 71	
 72	export const PageHeading: React.FC<PageHeadingProps> = (
 73	  props: PageHeadingProps
 74	) => {
 75	  const {
 76	    title,
 77	    menuActions,
 78	    breadcrumbs,
 79	    helpText,
 80	    statusIcon,
 81	    statusText,
 82	    kind,
 83	  } = props;
 84	
 85	  const hasMenuActions = !isEmpty(menuActions);
 86	  const showBreadcrumbs = breadcrumbs;
 87	  return (
 88	    <>
 89	      <Grid hasGutter>
 90	        <GridItem>
 91	          {showBreadcrumbs && (
 92	            <Split style={{ alignItems: "baseline" }}>
 93	              <SplitItem isFilled>
 94	                <BreadCrumbs breadcrumbs={breadcrumbs} />
 95	              </SplitItem>
 96	            </Split>
 97	          )}
 98	        </GridItem>
 99	
100	        <GridItem>
101	          <Flex
102	            alignItems={{ default: "alignItemsCenter" }}
103	            justifyContent={{ default: "justifyContentSpaceBetween" }}
104	          >
105	            <FlexItem>
106	              <Flex
107	                alignItems={{ default: "alignItemsCenter" }}
108	                spaceItems={{ default: "spaceItemsSm" }}
109	              >
110	                {kind && (
111	                  <ResourceIcon groupVersionKind={nodeHealthCheckKind} />
112	                )}
113	                <Title
114	                  headingLevel="h1"
115	                  size="xl"
116	                  data-test-id="resource-title"
117	                >
118	                  {title}
119	                </Title>
120	                {!!statusIcon && (
121	                  <ResourceStatus>
122	                    <StatusIconAndText title={statusText} icon={statusIcon} />
123	                  </ResourceStatus>
124	                )}
125	              </Flex>
126	              {helpText && (
127	                <TextContent>
128	                  <Text component={TextVariants.p}>{helpText}</Text>
129	                </TextContent>
130	              )}
131	            </FlexItem>
132	            {hasMenuActions && (
133	              <FlexItem>
134	                <ActionsMenu actions={menuActions} isKababToggle={false} />
135	              </FlexItem>
136	            )}
137	          </Flex>
138	        </GridItem>
139	      </Grid>
140	    </>
141	  );
142	};
143	
144	export const SectionHeading: React.SFC<SectionHeadingProps> = ({
145	  text,
146	  children,
147	  style,
148	  required,
149	  id,
150	}) => (
151	  <Title headingLevel="h2" id={id} style={style}>
152	    {text}
153	    {required && <span aria-hidden="true"> *</span>}
154	    {children}
155	  </Title>
156	);
157	
158	export type SectionHeadingProps = {
159	  children?: unknown;
160	  style?: unknown;
161	  text: string;
162	  required?: boolean;
163	  id?: string;
164	};

